package com.ecommerce.search.service;

import com.ecommerce.search.dto.BulkIndexResponse;
import com.ecommerce.search.model.Product;
import com.fasterxml.jackson.databind.ObjectMapper;
import com.fasterxml.jackson.datatype.jsr310.JavaTimeModule;
import lombok.RequiredArgsConstructor;
import lombok.extern.slf4j.Slf4j;
import org.elasticsearch.action.bulk.BulkRequest;
import org.elasticsearch.action.bulk.BulkResponse;
import org.elasticsearch.action.delete.DeleteRequest;
import org.elasticsearch.action.delete.DeleteResponse;
import org.elasticsearch.action.get.GetRequest;
import org.elasticsearch.action.get.GetResponse;
import org.elasticsearch.action.index.IndexRequest;
import org.elasticsearch.action.index.IndexResponse;
import org.elasticsearch.action.update.UpdateRequest;
import org.elasticsearch.action.update.UpdateResponse;
import org.elasticsearch.client.RequestOptions;
import org.elasticsearch.client.RestHighLevelClient;
import org.elasticsearch.xcontent.XContentType;
import org.springframework.stereotype.Service;

import java.io.IOException;
import java.time.LocalDateTime;
import java.util.*;
import java.util.stream.Collectors;

@Service
@RequiredArgsConstructor
@Slf4j
public class ProductIndexService {

    private final RestHighLevelClient client;
    private final ObjectMapper objectMapper;

    private ObjectMapper getMapper() {
        ObjectMapper mapper = new ObjectMapper();
        mapper.registerModule(new JavaTimeModule());
        return mapper;
    }

    public String indexProduct(Product product) throws IOException {
        if (product.getId() == null || product.getId().isEmpty()) {
            product.setId(UUID.randomUUID().toString());
        }
        product.setCreatedAt(LocalDateTime.now());
        product.setUpdatedAt(LocalDateTime.now());

        ObjectMapper mapper = getMapper();
        String json = mapper.writeValueAsString(product);

        IndexRequest request = new IndexRequest(IndexManagementService.PRODUCT_INDEX)
                .id(product.getId())
                .source(json, XContentType.JSON);

        IndexResponse response = client.index(request, RequestOptions.DEFAULT);
        log.info("Product indexed: id={}, result={}", product.getId(), response.getResult().name());
        return product.getId();
    }

    public Product getProduct(String id) throws IOException {
        GetRequest request = new GetRequest(IndexManagementService.PRODUCT_INDEX, id);
        GetResponse response = client.get(request, RequestOptions.DEFAULT);

        if (response.isExists()) {
            ObjectMapper mapper = getMapper();
            Product product = mapper.readValue(response.getSourceAsString(), Product.class);
            product.setId(response.getId());
            return product;
        }
        return null;
    }

    public String updateProduct(String id, Product product) throws IOException {
        product.setUpdatedAt(LocalDateTime.now());
        ObjectMapper mapper = getMapper();
        String json = mapper.writeValueAsString(product);

        UpdateRequest request = new UpdateRequest(IndexManagementService.PRODUCT_INDEX, id)
                .doc(json, XContentType.JSON)
                .docAsUpsert(true);

        UpdateResponse response = client.update(request, RequestOptions.DEFAULT);
        log.info("Product updated: id={}, result={}", id, response.getResult().name());
        return id;
    }

    public boolean deleteProduct(String id) throws IOException {
        DeleteRequest request = new DeleteRequest(IndexManagementService.PRODUCT_INDEX, id);
        DeleteResponse response = client.delete(request, RequestOptions.DEFAULT);
        log.info("Product deleted: id={}, result={}", id, response.getResult().name());
        return response.getResult().name().equals("DELETED");
    }

    public BulkIndexResponse bulkIndexProducts(List<Product> products) throws IOException {
        long startTime = System.currentTimeMillis();
        List<String> errors = new ArrayList<>();
        int successCount = 0;
        int failureCount = 0;

        ObjectMapper mapper = getMapper();

        // Process in batches of 500
        int batchSize = 500;
        for (int i = 0; i < products.size(); i += batchSize) {
            List<Product> batch = products.subList(i, Math.min(i + batchSize, products.size()));
            BulkRequest bulkRequest = new BulkRequest();

            for (Product product : batch) {
                if (product.getId() == null || product.getId().isEmpty()) {
                    product.setId(UUID.randomUUID().toString());
                }
                product.setCreatedAt(LocalDateTime.now());
                product.setUpdatedAt(LocalDateTime.now());

                String json = mapper.writeValueAsString(product);
                IndexRequest indexRequest = new IndexRequest(IndexManagementService.PRODUCT_INDEX)
                        .id(product.getId())
                        .source(json, XContentType.JSON);
                bulkRequest.add(indexRequest);
            }

            BulkResponse bulkResponse = client.bulk(bulkRequest, RequestOptions.DEFAULT);

            if (bulkResponse.hasFailures()) {
                Arrays.stream(bulkResponse.getItems()).forEach(item -> {
                    if (item.isFailed()) {
                        errors.add(String.format("Failed to index product %s: %s",
                                item.getId(), item.getFailureMessage()));
                    }
                });
                failureCount += (int) Arrays.stream(bulkResponse.getItems())
                        .filter(item -> item.isFailed()).count();
                successCount += batch.size() - failureCount;
            } else {
                successCount += batch.size();
            }
        }

        long timeTaken = System.currentTimeMillis() - startTime;
        log.info("Bulk indexing completed: total={}, success={}, failures={}, timeMs={}",
                products.size(), successCount, failureCount, timeTaken);

        return BulkIndexResponse.builder()
                .totalProcessed(products.size())
                .successCount(successCount)
                .failureCount(failureCount)
                .errors(errors)
                .timeTakenMs(timeTaken)
                .build();
    }

    public void partialUpdate(String id, Map<String, Object> fields) throws IOException {
        fields.put("updatedAt", LocalDateTime.now().toString());

        UpdateRequest request = new UpdateRequest(IndexManagementService.PRODUCT_INDEX, id)
                .doc(fields);

        UpdateResponse response = client.update(request, RequestOptions.DEFAULT);
        log.info("Product partially updated: id={}, result={}", id, response.getResult().name());
    }
}

